            $json['CpusetCpus']           = $this->cpusetCpus;
        }
        if (isset($this->cpusetMems)) {
            $json['CpusetMems']           = $this->cpusetMems;
        }
        if (isset($this->deviceCgroupRules)) {
            $json['DeviceCgroupRules']    = $this->deviceCgroupRules;
        }
        if (isset($this->devices)) {
            $json['Devices']              = $this->devices;
        }
        if (isset($this->diskQuota)) {
            $json['DiskQuota']            = $this->diskQuota;
        }
        if (isset($this->iOMaximumBandwidth)) {
            $json['IOMaximumBandwidth']   = $this->iOMaximumBandwidth;
        }
        if (isset($this->iOMaximumIOps)) {
            $json['IOMaximumIOps']        = $this->iOMaximumIOps;
        }
        if (isset($this->kernelMemory)) {
            $json['KernelMemory']         = $this->kernelMemory;
        }
        if (isset($this->memory)) {
            $json['Memory']               = $this->memory;
        }
        if (isset($this->memoryReservation)) {
            $json['MemoryReservation']    = $this->memoryReservation;
        }
        if (isset($this->memorySwap)) {
            $json['MemorySwap']           = $this->memorySwap;
        }
        if (isset($this->memorySwappiness)) {
            $json['MemorySwappiness']     = $this->memorySwappiness;
        }
        if (isset($this->nanoCPUs)) {
            $json['NanoCPUs']             = $this->nanoCPUs;
        }
        if (isset($this->oomKillDisable)) {
            $json['OomKillDisable']       = $this->oomKillDisable;
        }
        if (isset($this->pidsLimit)) {
            $json['PidsLimit']            = $this->pidsLimit;
        }
        if (isset($this->ulimits)) {
            $json['Ulimits']              = $this->ulimits;
        }
        if (isset($this->restartPolicy)) {
            $json['RestartPolicy']        = $this->restartPolicy;
        }

        return (!$asArrayWhenEmpty && empty($json)) ? new stdClass() : $json;
    }
}
